3	const BASE_PREMIUM_BY_ITEM_TYPE: Record<string, number> = {
4	  sword: 100,
5	  amulet: 60,
6	  staff: 80,
7	  potion: 40,
8	};
9	
10	type Item = { type: string };
11	type Step = { items: Item[] };
12	type Scenario = { steps: Step[] };
13	
14	const basePremiumFor = (item: Item): number =>
15	  BASE_PREMIUM_BY_ITEM_TYPE[item.type] ?? 0;
16	
17	const quotePremiumFor = (step: Step): number => {
18	  const itemsBaseTotal = step.items.reduce(
19	    (sum, item) => sum + basePremiumFor(item),
20	    0,
21	  );
22	  return itemsBaseTotal + PROCESSING_FEE;
23	};
24	
25	export const processScenario = (input: unknown): unknown => {
26	  const scenario = input as Scenario;
27	  return { results: [{ premium: quotePremiumFor(scenario.steps[0]) }] };
28	};
